patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 0633388cd411..c8f671aa42d3 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -2859,7 +2859,9 @@ Instruction *InstCombinerImpl::foldSelectOfBools(SelectInst &SI) {
       return SelectInst::Create(C, B, A);
     }
   }
-
+    // sel C, (sel C2, A, B), B -> sel (C && C2), A, B
+    // sel C, B, (sel C2, A, B) -> sel (C || C2), B, A
+    // (A similar pattern is handled in foldSelectOpOp, but for boolean types.)
   return nullptr;
 }

@@ -3130,6 +3132,14 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
         replaceOperand(SI, 1, TrueSI->getTrueValue());
         return &SI;
       }
+// Empty
+      if (TrueSI->getTrueValue() == FalseVal && TrueSI->hasOneUse()) {
+        Value *NotCond2 = Builder.CreateNot(TrueSI->getCondition());
+        Value *And = Builder.CreateLogicalAnd(CondVal, NotCond2);
+        replaceOperand(SI, 0, And);
+        replaceOperand(SI, 1, TrueSI->getFalseValue());
+        return &SI;
+      }
     }
   }
   if (SelectInst *FalseSI = dyn_cast<SelectInst>(FalseVal)) {
@@ -3140,13 +3150,118 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
           return nullptr;
         return replaceOperand(SI, 2, FalseSI->getFalseValue());
       }
-      // select(C0, a, select(C1, a, b)) -> select(C0|C1, a, b)
       if (FalseSI->getTrueValue() == TrueVal && FalseSI->hasOneUse()) {
         Value *Or = Builder.CreateLogicalOr(CondVal, FalseSI->getCondition());
         replaceOperand(SI, 0, Or);
         replaceOperand(SI, 2, FalseSI->getFalseValue());
         return &SI;
       }
+      if (FalseSI->getFalseValue() == TrueVal && FalseSI->hasOneUse()) {
+        Value *NotCond2 = Builder.CreateNot(FalseSI->getCondition());
+        Value *Or = Builder.CreateLogicalOr(CondVal, NotCond2);
+        replaceOperand(SI, 0, Or);
+        replaceOperand(SI, 2, FalseSI->getTrueValue());
+        return &SI;
+      }
+    }
+  }
+
+  Value *CondLHS, *CondRHS;
+  if (match(CondVal, m_LogicalAnd(m_Value(CondLHS), m_Value(CondRHS)))) {
+    if (auto *FalseSI = dyn_cast<SelectInst>(FalseVal)) {
+      if (FalseSI->getCondition() == CondLHS) {
+        if (FalseSI->hasOneUse()) {
+          Value *NewInnerSel = Builder.CreateSelect(CondRHS, TrueVal, FalseSI->getTrueValue());
+          return replaceInstUsesWith(SI, Builder.CreateSelect(CondLHS, NewInnerSel, FalseSI->getFalseValue()));
+        }
+      } else if (FalseSI->getCondition() == CondRHS) {
+        if (FalseSI->hasOneUse()) {
+          Value *NewInnerSel = Builder.CreateSelect(CondLHS, TrueVal, FalseSI->getTrueValue());
+          return replaceInstUsesWith(SI, Builder.CreateSelect(CondRHS, NewInnerSel, FalseSI->getFalseValue()));
+        }
+      } else if (match(FalseSI->getCondition(), m_Not(m_Specific(CondLHS)))) {
+        if (FalseSI->hasOneUse()) {
+          Value *NewInnerSel = Builder.CreateSelect(CondRHS, TrueVal, FalseSI->getFalseValue());
+          return replaceInstUsesWith(SI, Builder.CreateSelect(CondLHS, NewInnerSel, FalseSI->getTrueValue()));
+        }
+      } else if (match(FalseSI->getCondition(), m_Not(m_Specific(CondRHS)))) {
+        if (FalseSI->hasOneUse()) {
+          Value *NewInnerSel = Builder.CreateSelect(CondLHS, TrueVal, FalseSI->getFalseValue());
+          return replaceInstUsesWith(SI, Builder.CreateSelect(CondRHS, NewInnerSel, FalseSI->getTrueValue()));
+        }
+      }
+    }
+    if (auto *TrueSI = dyn_cast<SelectInst>(TrueVal)) {
+      if (match(CondLHS, m_Not(m_Specific(TrueSI->getCondition())))) {
+        if (TrueSI->hasOneUse()) {
+          Value *NewInnerSel = Builder.CreateSelect(CondRHS, TrueSI->getFalseValue(), FalseVal);
+          return replaceInstUsesWith(SI, Builder.CreateSelect(TrueSI->getCondition(), TrueSI->getTrueValue(), NewInnerSel));
+        }
+      } else if (match(CondRHS, m_Not(m_Specific(TrueSI->getCondition())))) {
+        if (TrueSI->hasOneUse()) {
+          Value *NewInnerSel = Builder.CreateSelect(CondLHS, TrueSI->getFalseValue(), FalseVal);
+          return replaceInstUsesWith(SI, Builder.CreateSelect(TrueSI->getCondition(), TrueSI->getTrueValue(), NewInnerSel));
+        }
+      } else if (match(TrueSI->getCondition(), m_Not(m_Specific(CondLHS)))) {
+        if (TrueSI->hasOneUse()) {
+          Value *NewInnerSel = Builder.CreateSelect(CondRHS, TrueSI->getTrueValue(), FalseVal);
+          return replaceInstUsesWith(SI, Builder.CreateSelect(CondLHS, TrueSI->getFalseValue(), NewInnerSel));
+        }
+      } else if (match(TrueSI->getCondition(), m_Not(m_Specific(CondRHS)))) {
+        if (TrueSI->hasOneUse()) {
+          Value *NewInnerSel = Builder.CreateSelect(CondLHS, TrueSI->getTrueValue(), FalseVal);
+          return replaceInstUsesWith(SI, Builder.CreateSelect(CondRHS, TrueSI->getFalseValue(), NewInnerSel));
+        }
+      }
+    }
+  }
+
+  if (match(CondVal, m_LogicalOr(m_Value(CondLHS), m_Value(CondRHS)))) {
+    if (auto *TrueSI = dyn_cast<SelectInst>(TrueVal)) {
+      if (TrueSI->getCondition() == CondLHS) {
+        if (TrueSI->hasOneUse()) {
+          Value *NewInnerSel = Builder.CreateSelect(CondRHS, TrueSI->getFalseValue(), FalseVal);
+          return replaceInstUsesWith(SI, Builder.CreateSelect(CondLHS, TrueSI->getTrueValue(), NewInnerSel));
+        }
+      } else if (TrueSI->getCondition() == CondRHS) {
+        if (TrueSI->hasOneUse()) {
+          Value *NewInnerSel = Builder.CreateSelect(CondLHS, TrueSI->getFalseValue(), FalseVal);
+          return replaceInstUsesWith(SI, Builder.CreateSelect(CondRHS, TrueSI->getTrueValue(), NewInnerSel));
+        }
+      } else if (match(TrueSI->getCondition(), m_Not(m_Specific(CondLHS)))) {
+        if (TrueSI->hasOneUse()) {
+          Value *NewInnerSel = Builder.CreateSelect(CondRHS, TrueSI->getTrueValue(), FalseVal);
+          return replaceInstUsesWith(SI, Builder.CreateSelect(CondLHS, TrueSI->getFalseValue(), NewInnerSel));
+        }
+      } else if (match(TrueSI->getCondition(), m_Not(m_Specific(CondRHS)))) {
+        if (TrueSI->hasOneUse()) {
+          Value *NewInnerSel = Builder.CreateSelect(CondLHS, TrueSI->getTrueValue(), FalseVal);
+          return replaceInstUsesWith(SI, Builder.CreateSelect(CondRHS, TrueSI->getFalseValue(), NewInnerSel));
+        }
+      }
+    }
+    if (auto *FalseSI = dyn_cast<SelectInst>(FalseVal)) {
+      if (match(CondLHS, m_Not(m_Specific(FalseSI->getCondition())))) {
+        if (FalseSI->hasOneUse()) {
+          Value *NewInnerSel = Builder.CreateSelect(CondRHS, TrueVal, FalseSI->getTrueValue());
+          return replaceInstUsesWith(SI, Builder.CreateSelect(FalseSI->getCondition(), NewInnerSel, FalseSI->getFalseValue()));
+        }
+      } else if (match(CondRHS, m_Not(m_Specific(FalseSI->getCondition())))) {
+        if (FalseSI->hasOneUse()) {
+          Value *NewInnerSel = Builder.CreateSelect(CondLHS, TrueVal, FalseSI->getTrueValue());
+          return replaceInstUsesWith(SI, Builder.CreateSelect(FalseSI->getCondition(), NewInnerSel, FalseSI->getFalseValue()));
+        }
+      } else if (match(FalseSI->getCondition(), m_Not(m_Specific(CondLHS)))) {
+        if (FalseSI->hasOneUse()) {
+          Value *NewInnerSel = Builder.CreateSelect(CondRHS, TrueVal, FalseSI->getFalseValue());
+          return replaceInstUsesWith(SI, Builder.CreateSelect(CondLHS, NewInnerSel, FalseSI->getTrueValue()));
+        }
+      } else if (match(FalseSI->getCondition(), m_Not(m_Specific(CondRHS)))) {
+        if (FalseSI->hasOneUse()) {
+          Value *NewInnerSel = Builder.CreateSelect(CondLHS, TrueVal, FalseSI->getFalseValue());
+          return replaceInstUsesWith(SI, Builder.CreateSelect(CondRHS, NewInnerSel, FalseSI->getTrueValue()));
+        }
+      }
     }
   }

